import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"25. Casual Employment","description":"","frontmatter":{"title":"25. Casual Employment","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["employment","classifications"]},"headers":[],"relativePath":"ebas/mspp/employment/25-casual-employment.md","filePath":"ebas/mspp/employment/25-casual-employment.md"}'),n={name:"ebas/mspp/employment/25-casual-employment.md"};function s(l,e,i,p,m,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_25-casual-employment" tabindex="-1">25. Casual Employment <a class="header-anchor" href="#_25-casual-employment" aria-label="Permalink to &quot;25. Casual Employment&quot;">​</a></h1><p>An Employer may employ casual Employees in any classification in this Agreement subject to this clause. A Casual Employee includes a Locum Pharmacist as defined in subclause 25.1 or 25.4.</p><p><strong>25.1</strong> Casual Employment</p><p><strong>a.</strong> In order to ensure the effective operation of services, each Employer will endeavour to meet service requirements through the employment of permanent Employees, either full time or, part time. An Employer may use Casual staff where the current permanent staff are not available.</p><p><strong>b.</strong> Where there is a need to fill rosters due to absence, part time Employees will be asked first if they want to work additional hours. If this is not possible the Employer should use Casual Employees as a last resort.</p><p><strong>c.</strong> A Casual Employee is a direct Employee engaged in relieving work of a casual nature and whose engagement is terminable by an Employer in accordance with the Employer’s requirements without the requirement of prior notice by either party. They are to be paid per hour worked an amount equal to 1/38 of the weekly salary as set out in this Agreement appropriate to the class of work performed plus 25%; or 75% on weekends and public holidays.</p><p><strong>25.2</strong> Minimum Engagement</p><p><strong>a.</strong> The minimum period of engagement of a Casual Employee is three (3) hours per day.</p><p><strong>b.</strong> Except for the provisions of clause 25.5 and as provided in <a href="/eba/ebas/mspp/leave/67-long-service-leave.html">clause 67.1b</a>, a Casual Employee is not entitled to Annual Leave, Long Service Leave, or Personal Leave</p><p><strong>25.3</strong> Casual Conversion</p><p><strong>a.</strong> Where a Casual Employee has worked shifts on a regular and systematic basis over a period of 26 weeks, the Employer and the Employee recognise that the Employee may be more properly classified as part-time or full-time.</p><p><strong>b.</strong> The Employee will not be considered rostered on a regular and systematic basis where these shifts are replacing an Employee on a short term absence (including but not limited to parental leave, long service leave, workers compensation leave, personal leave) or flexible work arrangement.</p><p><strong>c.</strong> Either the Employer or the Employee has the right to request in writing the conversion to full-time or part-time employment and that request will not be unreasonably refused by either party.</p><p><strong>d.</strong> Where such a conversion occurs, the Employee will be provided with a Letter of Appointment setting out the revised employment arrangements, including any period/s of casual employment with the Employer.</p><p><strong>e.</strong> Casual loading will cease and, subject to subclause 25.2b, any benefits relating to permanent employment will commence at the time of appointment to permanent status.</p><p><strong>f.</strong> This clause 25.3 is in addition to any requirement or entitlement to offer or request casual conversion under the Act.</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>25.4</strong> Locum Employment (Pharmacists Only)</p><p><strong>a.</strong> A Locum is a Pharmacist who is a temporary Employee engaged in work of a casual nature or to relieve any full-time or part-time Employees during their absences from work, and whose engagement is terminable by an Employer in accordance with the Employer’s requirements without the prior notice of either party.</p><p><strong>b.</strong> A Locum Employee shall be paid per hour worked an amount equal to 1/38th of the weekly wage prescribed for the class of work done with the addition of 25% provided that the provisions of <a href="/eba/ebas/mspp/hours-of-work/55-hours-of-work.html">clauses 55</a>-Hours of Work, 56-Shift Work and 59-Overtime - including Saturday and Sunday work, shall apply to Locum Employees.</p><p><strong>c.</strong> Locum Employees shall not be entitled to the provisions of clauses in this Agreement relation to Personal/carers leave, Termination of Employment, Annual Leave, Jury Service, or Examination Leave. Any NES entitlements continue to apply.</p><p><strong>25.5</strong> Unpaid Carer’s and Compassionate Leave Entitlement For Casuals</p><p><strong>a.</strong> Subject to the evidentiary and notice requirements in <a href="/eba/ebas/mspp/leave/64-personal-carer-s-leave.html">clause 64.7</a> Casual Employees are entitled to not be available to attend work, or to leave work:</p><p><strong>(i)</strong> Where a member of their immediate family or household requires care or support because of a personal illness or personal injury or due to an unexpected emergency, or the birth of a child; or</p><p><strong>(ii)</strong> when: <strong>(A)</strong> a member of the employee’s immediate family or household: (1) contracts or develops a personal illness or injury that poses a serious threat to their life; or (2) dies; or (3) loses a pregnancy after 20 weeks gestation; or <strong>(B)</strong> the Employee of their partner loses a pregnancy.</p><p><strong>b.</strong> The Employer and the Employee shall agree on the period for which the Employee will be entitled to not be available to attend work. In the absence of agreement, the Employee is entitled to not be available to attend work for up to two days per occasion. The Employee is not entitled to any payment for the period of non-attendance.</p><p><strong>c.</strong> An Employer must not fail to re-engage a Casual Employee because the Employee accessed the entitlements provided for in this clause. The rights of an Employer to engage or not to engage a Casual Employee are otherwise not affected.</p><p>Plain language terms: casual.</p>',28)])])}const y=t(n,[["render",s]]);export{c as __pageData,y as default};
